def-group:

    {{{ oval_metadata("The password expiration warning age should be set appropriately.", rule_title=rule_title) }}}
    {{% if product in [ 'slmicro6', 'sle16' ] %}}









    {{% else %}}



    {{% endif %}}


{{{
oval_param_in_file_variable_test(
    filepath=login_defs_path,
    parameter="PASS_WARN_AGE",
    pattern="^[\s]*(?i)(PASS_WARN_AGE[\s]+\d+)[\s]*(?:#.*)?$",
    regex_capture="PASS_WARN_AGE\s+(\d+)",
    variable="var_accounts_password_warn_age_login_defs",
    operation="greater than or equal",
    type="int",
    test_id="test_pass_warn_age"
)
}}}
{{% set login_defs_drop_in_config_dir = "/".join(login_defs_drop_in_path.split("/")[:-1]) %}}
{{{
oval_param_in_file_variable_test(
    filepath=login_defs_drop_in_config_dir,
    filename_regex=".*\.defs$",
    parameter="PASS_WARN_AGE",
    pattern="^[\s]*(?i)(PASS_WARN_AGE[\s]+\d+)[\s]*(?:#.*)?$",
    regex_capture="PASS_WARN_AGE\s+(\d+)",
    variable="var_accounts_password_warn_age_login_defs",
    operation="greater than or equal",
    type="int",
    test_id="test_pass_warn_age_logindefs_drop_in_path"
)
}}}






    {{{ login_defs_drop_in_config_dir }}}
    .*\.defs$
    ^\s*PASS_WARN_AGE\s*
    1
